        let _TEMP6 /* SDAI.LOGICAL */ = _TEMP4 || _TEMP5
        let _TEMP7 /* SDAI.LOGICAL */ = SELF.U2 > SELF.U1
        let _TEMP8 /* SDAI.LOGICAL */ = SELF.USENSE .==. SDAI.FORCE_OPTIONAL(_TEMP7)
        let _TEMP9 /* SDAI.LOGICAL */ = _TEMP6 || _TEMP8
        return _TEMP9
      }
      public static func WHERE_wr4(SELF: eRECTANGULAR_TRIMMED_SURFACE.PRef?) -> SDAI.LOGICAL {
        guard let SELF = SELF else { return SDAI.UNKNOWN }

        let _TEMP1 /* SDAI.LOGICAL */ = SDAI.TYPEOF( SELF.BASIS_SURFACE, IS: eSPHERICAL_SURFACE.self )
        let _TEMP2 /* SDAI.LOGICAL */ = SDAI.TYPEOF( SELF.BASIS_SURFACE, IS: eTOROIDAL_SURFACE.self )
        let _TEMP3 /* SDAI.LOGICAL */ = _TEMP1 || _TEMP2
        let _TEMP4 /* SDAI.LOGICAL */ = SELF.V2 > SELF.V1
        let _TEMP5 /* SDAI.LOGICAL */ = SELF.VSENSE .==. SDAI.FORCE_OPTIONAL(_TEMP4)
        let _TEMP6 /* SDAI.LOGICAL */ = _TEMP3 || _TEMP5
        return _TEMP6
      }

      //EXPRESS IMPLICIT PARTIAL ENTITY CONSTRUCTOR
      /// initialize from explicit attribute values
      public init(
        BASIS_SURFACE: eSURFACE.PRef, 
        U1: tPARAMETER_VALUE, 
        U2: tPARAMETER_VALUE, 
        V1: tPARAMETER_VALUE, 
        V2: tPARAMETER_VALUE, 
        USENSE: SDAI.BOOLEAN, 
        VSENSE: SDAI.BOOLEAN
      ) {

        self._basis_surface = BASIS_SURFACE
        self._u1 = U1
        self._u2 = U2
        self._v1 = V1
        self._v2 = V2
        self._usense = USENSE
        self._vsense = VSENSE

        super.init(asAbstractSuperclass:())
      }

      //PARTIAL ENTITY COPY CONSTRUCTOR
      /// copy constructor
      public required convenience init(from original:SDAI.PartialEntity) {
        let original = original as! Self
        self.init( BASIS_SURFACE: original._basis_surface, U1: original._u1, U2: original._u2, V1: original._v1, V2: original._v2, USENSE: original._usense, VSENSE: original._vsense )
      }

      //p21 PARTIAL ENTITY CONSTRUCTOR
      /// initialize from ISO 10303-21 exchange structure parameters
      public required convenience init?(
        parameters: [P21Decode.ExchangeStructure.Parameter],
        exchangeStructure: P21Decode.ExchangeStructure
      ) {
        let numParams = 7
        guard parameters.count == numParams
        else { exchangeStructure.error = "number of p21 parameters(\(parameters.count)) are different from expected(\(numParams)) for partial entity(\(Self.entityName)) constructor"; return nil }

        guard case .success(let p0) = exchangeStructure.recoverRequiredParameter(as: eSURFACE.PRef.self, from: parameters[0])
        else { exchangeStructure.add(errorContext: "while recovering parameter [0]BASIS_SURFACE for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p1) = exchangeStructure.recoverRequiredParameter(as: tPARAMETER_VALUE.self, from: parameters[1])
        else { exchangeStructure.add(errorContext: "while recovering parameter [1]U1 for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p2) = exchangeStructure.recoverRequiredParameter(as: tPARAMETER_VALUE.self, from: parameters[2])
        else { exchangeStructure.add(errorContext: "while recovering parameter [2]U2 for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p3) = exchangeStructure.recoverRequiredParameter(as: tPARAMETER_VALUE.self, from: parameters[3])
        else { exchangeStructure.add(errorContext: "while recovering parameter [3]V1 for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p4) = exchangeStructure.recoverRequiredParameter(as: tPARAMETER_VALUE.self, from: parameters[4])
        else { exchangeStructure.add(errorContext: "while recovering parameter [4]V2 for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p5) = exchangeStructure.recoverRequiredParameter(as: SDAI.BOOLEAN.self, from: parameters[5])
        else { exchangeStructure.add(errorContext: "while recovering parameter [5]USENSE for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p6) = exchangeStructure.recoverRequiredParameter(as: SDAI.BOOLEAN.self, from: parameters[6])
        else { exchangeStructure.add(errorContext: "while recovering parameter [6]VSENSE for partial entity(\(Self.entityName)) constructor"); return nil }

        self.init( BASIS_SURFACE: p0, U1: p1, U2: p2, V1: p3, V2: p4, USENSE: p5, VSENSE: p6 )
      }
    }
